# main.tf

resource "aws_s3_bucket" "data_lake" {
  bucket = "my-company-data-lake"

  tags = {
    Environment = "production"
    Team        = "data-engineering"
  }
}

resource "aws_s3_bucket_versioning" "data_lake" {
  bucket = aws_s3_bucket.data_lake.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_glue_job" "daily_revenue" {
  name     = "daily-revenue-transform"
  role_arn = aws_iam_role.glue_role.arn

  command {
    script_location = "s3://${aws_s3_bucket.data_lake.bucket}/scripts/glue_job.py"
    python_version  = "3"
  }

  default_arguments = {
    "--job-language"        = "python"
    "--enable-metrics"      = ""
    "--enable-continuous-cloudwatch-log" = "true"
    "--source_bucket"       = aws_s3_bucket.data_lake.bucket
    "--target_bucket"       = aws_s3_bucket.data_lake.bucket
  }

  max_retries       = 2
  timeout           = 120  # minutes
  number_of_workers = 10
  worker_type       = "G.1X"  # 4 vCPU, 16 GB RAM per worker
}
